var apiKey = getVar('runway_api_key');
if (!apiKey) return JSON.stringify({error: "Runway API key not configured. Set the 'runway_api_key' variable."});

var duration = Math.round(args.duration || 5);
if (duration < 2) duration = 2;
if (duration > 10) duration = 10;
var ratio = args.ratio || '720:1280';
var model = args.model || 'gen4.5';

// Validate model
var validModels = ['gen4.5', 'veo3.1', 'veo3.1_fast', 'veo3'];
if (validModels.indexOf(model) === -1) {
  return JSON.stringify({error: 'Invalid model for text_to_video. Valid models: ' + validModels.join(', ') + '. Got: ' + model});
}

var payload = JSON.stringify({
  promptText: args.prompt,
  model: model,
  duration: duration,
  ratio: ratio
});

var resp = httpPost('https://api.dev.runwayml.com/v1/text_to_video', payload, {
  'Authorization': 'Bearer ' + apiKey,
  'Content-Type': 'application/json',
  'X-Runway-Version': '2024-11-06'
});

if (resp.status !== 200 && resp.status !== 201) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'Runway API error (HTTP ' + resp.status + '): ' + errBody});
}

var taskData = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;
var taskId = taskData.id;

// Poll for completion (max 60 attempts * 5s = 5 minutes)
for (var i = 0; i < 60; i++) {
  // Wait 5 seconds between polls
  var waitResp = httpGet('https://httpstat.us/200?sleep=5000', {});

  var statusResp = httpGet('https://api.dev.runwayml.com/v1/tasks/' + taskId, {
    'Authorization': 'Bearer ' + apiKey,
    'X-Runway-Version': '2024-11-06'
  });

  var statusData = typeof statusResp.body === 'string' ? jsonParse(statusResp.body) : statusResp.body;

  if (statusData.status === 'SUCCEEDED') {
    return JSON.stringify({
      video_url: statusData.output[0],
      task_id: taskId,
      duration_seconds: duration
    }, null, 2);
  }

  if (statusData.status === 'FAILED') {
    return JSON.stringify({
      error: 'Video generation failed: ' + (statusData.failure || statusData.failureReason || 'unknown error'),
      task_id: taskId
    });
  }
}

return JSON.stringify({
  error: 'Video generation timed out after 5 minutes. Use check_video_status to poll manually.',
  task_id: taskId
});

