var resp = httpGet('https://api.dev.runwayml.com/v1/tasks/' + args.task_id, {
  'Authorization': 'Bearer ' + apiKey,
  'X-Runway-Version': '2024-11-06'
});

if (resp.status !== 200) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'Runway API error (HTTP ' + resp.status + '): ' + errBody});
}

var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;

var result = {
  task_id: args.task_id,
  status: data.status
};

if (data.status === 'SUCCEEDED') {
  result.video_url = data.output[0];
} else if (data.status === 'FAILED') {
  result.error = data.failure || data.failureReason || 'unknown error';
} else if (data.progress) {
  result.progress = data.progress;
}

return JSON.stringify(result, null, 2);
